const byCountry = (() => {
  const map = new Map()
  for (const row of WORLD_OBSERVATIONS) {
    if (!map.has(row.iso3)) map.set(row.iso3, [])
    map.get(row.iso3).push(row)
  }
  return map
})()

// Default country set used by the longevity-trend question — one country per
// region so the line chart split stays legible.
export const TREND_COUNTRIES = ["KOR", "CHN", "BRA", "IND", "NGA"]

// The pure view-builders below each shape the canonical observations into a
// *focused* question dataset. The fields included are deliberate: they are the
// only signal the engine sees, so its profiling lands on the field roles the
// question intends (country as the thing compared, year as the time axis, the
// indicator as the measure) rather than seizing on an incidental lower-
// cardinality column. The question chooses the fields; the engine chooses the
// form.

// A single country's time series for one indicator: { year, <field> }. Kept to
// two fields so the description layer narrates one clean, correct trajectory
// instead of pooling several series.
export function singleCountryTrend(iso = "KOR", field = "lifeExpectancy") {
  return (byCountry.get(iso) || [])
    .filter((row) => row[field] != null)
    .map((row) => ({ year: row.year, [field]: row[field] }))
}

// Sum of one indicator across the countries in each group (region or income),
// as { <dimension>, <field> } — a part-to-whole shape over the sixteen-country
// sample. Income (four groups) reads cleanly as a pie; region (seven) as a bar.
export function shareByGroup(dimension = "income", field = "population", year = WORLD_LATEST_YEAR) {
  const totals = new Map()
  for (const country of WORLD_COUNTRIES) {
    const row = (byCountry.get(country.iso3) || []).find((r) => r.year === year)
    if (!row || row[field] == null) continue
    totals.set(country[dimension], (totals.get(country[dimension]) || 0) + row[field])
  }
  return [...totals].map(([group, value]) => ({ [dimension]: group, [field]: value }))
}

// A multi-series time trend for one indicator: { year, country, <field> } rows,
// ready for a line chart split by country.
export function multiCountryTrend(field = "lifeExpectancy", isoList = TREND_COUNTRIES) {
  const rows = []
  for (const iso of isoList) {
    const meta = WORLD_COUNTRIES.find((c) => c.iso3 === iso)
    for (const row of byCountry.get(iso) || []) {
      if (row[field] == null) continue
      rows.push({ year: row.year, country: meta ? meta.name : iso, [field]: row[field] })
    }
  }
  return rows
}

// One slim { country, <field> } row per country at a given year — the shape a
// ranking or comparison question wants, so the engine bars by country.
export function rankByCountry(field = "lifeExpectancy", year = WORLD_LATEST_YEAR) {
  const rows = []
  for (const country of WORLD_COUNTRIES) {
    const row = (byCountry.get(country.iso3) || []).find((r) => r.year === year)
    if (!row || row[field] == null) continue
    rows.push({ country: country.name, [field]: row[field] })
  }
  return rows
}

// A two-measure cross-section for relationship questions: one row per country
// with exactly two numeric fields (plus country/region for tooltips), so the
// engine reads a clean correlation rather than guessing among many numerics.
export function crossSection(fields, year = WORLD_LATEST_YEAR) {
  const rows = []
  for (const country of WORLD_COUNTRIES) {
    const row = (byCountry.get(country.iso3) || []).find((r) => r.year === year)
    if (!row) continue
    const out = { country: country.name, region: country.region }
    let complete = true
    for (const field of fields) {
      if (row[field] == null) { complete = false; break }
      out[field] = row[field]
    }
    if (complete) rows.push(out)
  }
  return rows
}

// Every country-year value of one indicator as a distribution sample:
// { country, <field> }. ~500 numeric observations.
export function distributionSample(field = "lifeExpectancy") {
  return WORLD_OBSERVATIONS.filter((r) => r[field] != null).map((r) => ({
    country: r.country,
    [field]: r[field],
  }))
}
